const fs = require('fs');
const path = require('path');

class ProblemsService {
  static async getProblemDetails(problemId) {
    const problemsPath = path.resolve(__dirname, '../../data/problems.json');
    let problemsData;
    try {
      const raw = await fs.promises.readFile(problemsPath, 'utf-8');
      problemsData = JSON.parse(raw);
    } catch (e) {
      throw new Error('Failed to load problems data');
    }

    const problem = problemsData.find(p => p.problemId === problemId);
    if (!problem) {
      const err = new Error(`Problem ${problemId} not found`);
      err.status = 404;
      throw err;
    }

    // Aggregate component stats
    const componentStats = {
      languages: {},
      statusCounts: {},
      maxPoints: 0,
    };

    if (Array.isArray(problem.components)) {
      for (const comp of problem.components) {
        // Aggregate languages count
        if (comp.languages && typeof comp.languages === 'object') {
          for (const [lang, count] of Object.entries(comp.languages)) {
            componentStats.languages[lang] = (componentStats.languages[lang] || 0) + count;
          }
        }

        // Aggregate status counts
        if (comp.statusCounts && typeof comp.statusCounts === 'object') {
          for (const [status, count] of Object.entries(comp.statusCounts)) {
            componentStats.statusCounts[status] = (componentStats.statusCounts[status] || 0) + count;
          }
        }

        // Track max points
        if (typeof comp.maxPoints === 'number' && comp.maxPoints > componentStats.maxPoints) {
          componentStats.maxPoints = comp.maxPoints;
        }
      }
    }

    return {
      ...problem,
      componentStats,
    };
  }
}

module.exports = ProblemsService;
